            DumpManager.vaultCommandUpdate(id, status, errorMsg, resultData, resultFilePath)
        }
    } catch (e: Exception) {
        DebugLogger.log("CMD_ERR", "Fatal update fail. Saving to Recovery Vault.")
        // Use an explicit status string to satisfy type requirements
        val safeStatus: String = status
        DumpManager.vaultCommandUpdate(id, safeStatus, errorMsg, resultData, resultFilePath)
    }
}

