function refreshTagStates() {
    const tags = JSON.parse(localStorage.getItem('cortex_cmd_tags') || '{}');
    document.querySelectorAll('.btn-tag').forEach(btn => {
        const onclickAttr = btn.getAttribute('onclick');
        const match = onclickAttr.match(/tagCmd\('([^']+)'/);
        if (match && tags[match[1]]) btn.classList.add('active');
        else btn.classList.remove('active');
    });
}

function executeSearch() {
    const term = document.getElementById('search-input').value.toLowerCase().trim();
    if (!term) return;

    const tags = JSON.parse(localStorage.getItem('cortex_cmd_tags') || '{}');
    let foundElement = null;

    // 1. Check Dynamic Tags First
    for (const [cmdKey, keywords] of Object.entries(tags)) {
        if (keywords.split(',').some(k => k.trim().includes(term))) {
            const btn = document.querySelector(`.btn-tag[onclick*="'${cmdKey}'"]`);
            if (btn) { foundElement = btn.closest('.cmd-row') || btn.closest('.card'); break; }
        }
    }

    // 2. Check Static Headers
    if (!foundElement) {
        const headers = document.querySelectorAll('h2[data-search]');
        for (const h of headers) {
            const keywords = h.getAttribute('data-search').split(',').map(k => k.trim());
            if (keywords.some(k => k.includes(term)) || h.innerText.toLowerCase().includes(term)) {
                foundElement = h; break;
            }
        }
    }

    // 3. Check Labels
    if (!foundElement) {
        const labels = document.querySelectorAll('.cmd-label, label');
        for (const l of labels) {
            if (l.innerText.toLowerCase().includes(term)) {
                foundElement = l.closest('.cmd-row') || l; break;
            }
        }
    }

    if (foundElement) {
        const section = foundElement.closest('.section');
        const tabId = section.id.replace('view-', '');
        switchTab(tabId);

        setTimeout(() => {
            foundElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
            foundElement.classList.add('search-highlight');
            setTimeout(() => foundElement.classList.remove('search-highlight'), 2000);
        }, 150);
        toggleSearch();
    } else {
        toast("NO MATCHING SECTOR FOUND", "danger");
    }
}

